#!/usr/bin/env python3
"""
MKT Context — 2 Kings chapters 18–19 (fill: verse-sparse chapters)
Run: python3 scripts/zc-context-2kings-fill-18-19.py

Covers missing verses:
  ch18: v4, v13 exist; fills v1–3, v5–12, v14–37  (35 missing)
  ch19: v35 exists; fills v1–34, v36–37           (36 missing)

Historical context:
  - Hezekiah's reign (c.715–686 BCE), one of the best-attested Judean kings
  - Sennacherib's third campaign (701 BCE) — documented in Sennacherib's Annals
  - Lachish siege reliefs (British Museum), Siloam Tunnel inscription
  - The three Assyrian officials (Tartan, Rab-saris, Rabshakeh) and their titles
  - Tirhakah (Taharqa, 25th dynasty pharaoh) — chronological debate
  - Sennacherib's death confirmed in Babylonian Chronicle (681 BCE)
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

TWO_KINGS_CONTEXT = {
    "18": {
        "1": "<p><b>v1 — Chronological synchronism: Hezekiah's accession</b><br>The accession of Hezekiah is synchronized with the third year of Hoshea king of Israel. The dual-synchronism system (northern king dated by the southern and vice versa) reflects the practice of the Deuteronomistic Historian working from parallel court records. Hezekiah's dates are debated: the dominant scholarly reconstruction places his accession c. 715 BCE, though some put it as early as 727 BCE based on internal biblical synchronisms. The chronological discrepancies in the Kings data are among the most discussed in OT scholarship.</p>",
        "2": "<p><b>v2 — Twenty-five years old; twenty-nine year reign; mother Abi</b><br>The regnal formula for Hezekiah: age at accession (25), length of reign (29 years), mother's name (Abi/Abijah daughter of Zechariah). The Deuteronomistic regnal formula has been applied consistently throughout Kings — age, reign length, mother's name (for Judean kings), and theological evaluation. 'Abi daughter of Zechariah' — the Zechariah is likely distinct from the prophet; the Judean court practice of recording the queen mother's name (<i>gevirah</i>) reflects her institutional significance in the Judean monarchy.</p>",
        "3": "<p><b>v3 — Theological evaluation: did right as David did</b><br>Hezekiah receives the highest possible Deuteronomistic commendation: he did what was right in the eyes of the LORD <i>ke-khol asher asah David aviv</i> — just as David his ancestor did. David is the standard against which all Judean kings are measured; only Hezekiah (here) and Josiah (2 Kings 22:2) receive unqualified Davidic comparison. This evaluation is unique even among the &#x201C;good&#x201D; kings, most of whom receive the qualified formula &#x201C;right in the eyes of the LORD, though the high places were not removed.&#x201D;</p>",
        "5": "<p><b>v5 — Unique superlative: no king like him before or after</b><br>The superlative claim for Hezekiah — &#x201C;among all the kings of Judah there was none like him, neither before nor after him&#x201D; — is precisely the same formula used for Solomon (1 Kings 3:12) and later for Josiah (2 Kings 23:25). The repetition of this absolute formula for three kings is a literary tension within Kings itself; commentators have long noted that the same formula cannot logically apply to all three. The Deuteronomist's purpose seems to be situational superlative: Hezekiah surpasses all others in trust; Josiah in covenant-adherence; Solomon in wisdom.</p>",
        "6": "<p><b>v6 — He clung to the LORD; did not depart from his commandments</b><br>The phrase <i>dabaq ba-YHWH</i> (he clung to / adhered to the LORD) is Deuteronomic covenant language (Deut 10:20; 11:22; 13:4; 30:20): the word <i>dabaq</i> (cling/cleave) describes the proper covenantal posture. The same word is used in Gen 2:24 (husband clings to wife) — covenant loyalty has the intensity of marital commitment. Hezekiah is described as the model of covenant <i>davaq</i>. The negative counterpart — not turning aside from the commandments given to Moses — echoes the Deuteronomic formula of Joshua 23:6.</p>",
        "7": "<p><b>v7 — The LORD was with him; he rebelled against Assyria</b><br>The divine-presence formula <i>ve-YHWH imo</i> (the LORD was with him) appears for Hezekiah just as it appeared for David and Joseph. In the ANE framework, royal success was interpreted as divine favor; for the Deuteronomist, this formula means covenant blessing is operationally present. The rebellion against Assyria — <i>marat be-melekh Ashur</i> (he rebelled against the king of Assyria) — refers to Hezekiah's decision to withhold tribute as part of his anti-Assyrian coalition (c. 705 BCE, when Sargon II died and Sennacherib's accession created instability throughout the empire).</p>",
        "8": "<p><b>v8 — Hezekiah defeats Philistines to Gaza</b><br>Hezekiah's Philistine campaign (from watchtower to fortified city — a merism for the full range of settlements) demonstrates military strength consistent with his independence from Assyrian control. Archaeological excavations at sites like Tell es-Safi (Gath), Ashdod, and Ekron show destruction layers potentially linked to this campaign. The Assyrian records describe Padi king of Ekron as a pro-Assyrian vassal whom Hezekiah imprisoned — part of the anti-Assyrian coalition that preceded Sennacherib's 701 campaign.</p>",
        "9": "<p><b>v9 — The fall of Samaria reviewed (Shalmaneser's siege, fourth year of Hezekiah)</b><br>The narrator inserts a retrospective review of Samaria's fall (cf. 2 Kings 17:3-6), synchronizing it with Hezekiah's reign. In the fourth year of Hezekiah (= seventh year of Hoshea), Shalmaneser V besieged Samaria. The dual synchronism frames the Northern Kingdom's end as a backdrop to Hezekiah's reform — what happened to the north is the threat the south faces if it does not reform. Shalmaneser V (727–722 BCE) began the siege; Sargon II (722–705 BCE) claims the conquest in his inscriptions.</p>",
        "10": "<p><b>v10 — After three years, Samaria fell in the sixth year of Hezekiah</b><br>The three-year siege (724–722 BCE) ended in Samaria's fall — the sixth year of Hezekiah in the Deuteronomist's reckoning. This synchronism is significant: Sargon II's Annals record the deportation of 27,290 inhabitants of Samaria. The capital of the Northern Kingdom ceased to exist as an Israelite city; it became an Assyrian provincial capital (Samerina). The Deuteronomist's theological interpretation follows immediately in v12: the fall was the result of covenant violation.</p>",
        "11": "<p><b>v11 — The deportation: Halah, Habor, Gozan, Median cities</b><br>The deportation destinations — Halah (<i>Chalach</i>), the Habor River (<i>Nahar Gozan</i>), and Median cities — are identifiable in Assyrian records. Halah is possibly Chalcis in northern Mesopotamia; the Habor (mod. Khabur River in Syria) was a well-known deportation zone; Gozan (mod. Tell Halaf) is confirmed as an Assyrian administrative center by excavations. The &#x201C;Median cities&#x201D; reflect Assyrian policy of populating the eastern frontier with deportees. This is the Assyrian <i>māt Māda</i> (land of the Medes), where deported Israelites were settled as buffer-population.</p>",
        "12": "<p><b>v12 — Theological explanation: they violated the covenant of Moses</b><br>The Deuteronomistic explanation: Samaria fell because the people did not listen to the LORD and violated his covenant — <i>et kol asher tzivah Moshe eved YHWH</i> (all that Moses the servant of the LORD commanded). This is the Deuteronomistic History's master-key: national catastrophe is the inevitable consequence of covenant violation. The theologian-historian is not claiming that Samaria&#x2019;s fall was surprising — it was the predicted outcome of the covenant curses in Deuteronomy 28. History and theology are integrated: geopolitical events are covenantal events.</p>",
        "14": "<p><b>v14 — Hezekiah submits to Sennacherib at Lachish</b><br>After Sennacherib's invasion captures all the fortified cities of Judah, Hezekiah capitulates and sends tribute. Lachish (<i>Lakhish</i>) was Sennacherib's military headquarters for the Judean campaign — not Jerusalem, which he apparently chose not to assault directly after the tribute payment and subsequent events. The Lachish siege is one of the best-documented events of the OT era: Sennacherib's palace at Nineveh (modern Kuyunjik) contained a large relief showing the siege in detail, now in the British Museum (Room 36). Hezekiah's words — &#x201C;I have sinned; withdraw and I will pay whatever you impose&#x201D; — are a formal capitulation formula.</p>",
        "15": "<p><b>v15 — All the silver from the temple and treasury handed over</b><br>Hezekiah empties the temple treasury and royal treasury of silver. Sennacherib's Annals (Taylor Prism) record the tribute: &#x201C;30 talents of gold, 800 talents of silver, precious stones, antimony, large cuts of red stone, couches inlaid with ivory, elephant hides, ebony-wood, boxwood and all kinds of valuable treasures.&#x201D; The MT of Kings says 300 talents of silver — Sennacherib says 800. The discrepancy (a ×2.67 difference) is discussed by scholars: different talent standards, different counting methods, or the Assyrian record including tribute collected over multiple periods are all proposed.</p>",
        "16": "<p><b>v16 — Gold stripped from temple doors and doorposts</b><br>Hezekiah goes further — stripping the gold overlay (<i>tzipui</i>) from the temple doors and doorposts that he himself had plated. The verb <i>qitztzetz</i> (to cut off/strip) indicates a physical removal process. The doors and doorposts (<i>daliyot ha-hekhal ve-et ha-imot</i>) likely refer to the monumental cedar-and-gold entrance of Solomon's temple described in 1 Kings 6-7. The gold that took generations to accumulate is stripped in a crisis. Sennacherib's Annals record receiving this precious metal as part of the tribute, confirming the general picture.</p>",
        "17": "<p><b>v17 — The three Assyrian officials and the delegation to Jerusalem</b><br>Sennacherib sends three high officials — the <i>Tartan</i>, <i>Rab-saris</i>, and <i>Rabshakeh</i> — from Lachish to Jerusalem. These are Assyrian titles, not personal names: <i>turtānu</i> (field marshal/second-in-command), <i>rāb ša rēši</i> (palace chief, possibly the chief eunuch), and <i>rāb šāqê</i> (chief cupbearer/officer, often serving as a diplomatic envoy). The delegation comes with a <i>chayil kaved</i> (heavy/massive force) — a military escort sufficient to intimidate. They stop at the Fuller's Field (<i>sedeh ha-kavvas</i>) — the same site where Isaiah confronted Ahaz (Isa 7:3).</p>",
        "18": "<p><b>v18 — The Judean delegation: Eliakim, Shebna, Joah</b><br>The Judean negotiating team consists of three court officials: Eliakim son of Hilkiah (palace administrator, <i>asher al ha-bayit</i>), Shebna the secretary (<i>sofer</i>), and Joah son of Asaph the recorder (<i>mazkir</i>). Isaiah 22:15-25 contains an oracle specifically about Shebna and Eliakim — Shebna was rebuked as overreaching his station, and Eliakim was promised his place. That oracle appears to precede ch18 chronologically; here we see Eliakim in his new role after Shebna's demotion from palace administrator to secretary. These are documented court officials whose titles match the administrative vocabulary of the period.</p>",
        "19": "<p><b>v19 — Rabshakeh's opening challenge: 'What is the basis of this trust?'</b><br>The Rabshakeh delivers his message in the third person on behalf of the &#x201C;great king, the king of Assyria&#x201D; (<i>ha-melekh ha-gadol melekh Ashur</i>) — the standard Assyrian royal title used in official documents. The question <i>'al-mah habitachon ha-zeh'</i> (what is this confidence?) is a rhetorical assault on Judah's basis for resistance. The speech is psychologically sophisticated propaganda: it analyzes and systematically destroys each possible source of trust (Egypt, military capacity, the LORD) before offering an alternative (Assyrian benevolence). The Rabshakeh speaks Hebrew fluently — evidence of Assyria's use of diplomats who could communicate directly with subject populations.</p>",
        "20": "<p><b>v20 — Empty words: strategy and military strength without substance</b><br>The Rabshakeh dismisses Hezekiah's talk of strategy and military power as <i>devar sefatayim</i> (words of lips only — empty talk). This rhetorical move — identifying apparent strength as illusory — is classic siege warfare psychology. The Assyrian empire had developed sophisticated propaganda techniques to undermine the morale of besieged cities before assault. The Rabshakeh's speech can be read as a textbook example of ancient psychological warfare, designed to create defection and capitulation without costly direct assault.</p>",
        "21": "<p><b>v21 — Egypt is a broken reed: the Nile staff metaphor</b><br>The comparison of Egypt to a <i>qaneh haratzutz</i> (broken reed / cracked staff) is a vivid image of unreliable support. A reed staff that shatters when leaned upon not only fails to support — it wounds the hand that trusts it. This image is also used in Ezekiel 29:6-7 (Egypt as a &#x201C;staff of reed&#x201D;). The Rabshakeh's political analysis proved accurate: Egypt's 25th dynasty support was inconsistent, and Tirhakah's forces (v9) were turned back by Sennacherib without decisive engagement. Politically, Egypt regularly encouraged small Levantine states to revolt against Assyria but consistently failed to provide adequate military backing.</p>",
        "22": "<p><b>v22 — Twisted logic: the LORD whose high places Hezekiah removed</b><br>The Rabshakeh's most sophisticated argument: Hezekiah removed the high places and altars, so where will people worship? — implying the LORD is angered by Hezekiah's reforms. This argument reflects either misunderstanding of Yahwistic theology (not distinguishing the high-place removal as centralization to Jerusalem) or deliberate distortion. The Rabshakeh's awareness of Hezekiah's reforms is historically plausible — Assyrian intelligence networks monitored subject states. The argument was effective propaganda precisely because it exploited popular attachment to local worship sites that Hezekiah had abolished.</p>",
        "23": "<p><b>v23 — The horse wager: can you find two thousand riders?</b><br>The Rabshakeh's mock offer — I will give you 2,000 horses if you can find riders — targets a specific Judean military weakness. Judah's cavalry was limited; Israel's horse procurement (which Solomon began) had been ongoing, but Judah remained less cavalry-heavy than the major powers. The taunt that Judah cannot field enough trained cavalry to mount even 2,000 horses exposes the military disproportion between a small Levantine kingdom and the Assyrian superpower, whose cavalry forces numbered in the tens of thousands.</p>",
        "24": "<p><b>v24 — Cannot repel one of the least officers; Egypt's chariots are useless</b><br>The military argument continues: Judah cannot hold back even the least of Assyria's commanders, yet relies on Egypt for chariots and cavalry. The Egyptian alliance (which Hezekiah had pursued) is explicitly named as the military backup plan — and dismissed as inadequate. The Assyrian army in 701 BCE was the most powerful military force in the ancient Near East: Sennacherib's Annals describe the siege of 46 Judean cities. The Rabshakeh's military assessment of Judah's weakness was objectively accurate.</p>",
        "25": "<p><b>v25 — The LORD commanded me to come against this land</b><br>The most audacious claim in the Rabshakeh's speech: <i>YHWH amar elai aleh el ha-aretz ha-zot ve-hashchiteha</i> — 'The LORD told me: go up against this land and destroy it.' Whether this reflects (1) knowledge of Isaiah's oracles about Assyria as the rod of God's anger (Isa 10:5-6), (2) genuine ANE political theology (all conquests are divinely authorized), or (3) pure bluff is debated. The claim creates maximum psychological confusion: if YHWH has commissioned this invasion, resistance is rebellion against the divine will. It appropriates the covenantal framework itself as a weapon against Hezekiah's piety.</p>",
        "26": "<p><b>v26 — Speak in Aramaic, not Hebrew</b><br>The Judean officials' request to use Aramaic (<i>Arami</i>) rather than Hebrew (<i>Yehudit</i> — Judean/Hebrew) is revealing: they understood both languages, and so did the Rabshakeh. Aramaic was the diplomatic and commercial lingua franca of the late Assyrian empire — what Latin was to medieval Europe or English to modern diplomacy. Hebrew was the vernacular spoken by the people on the walls. The officials were trying to contain the Rabshakeh's psychological warfare to an elite diplomatic channel and prevent it from reaching the civilian population.</p>",
        "27": "<p><b>v27 — The speech is for the men on the wall too</b><br>The Rabshakeh refuses to restrict his message to the officials — his audience is precisely the civilian population (<i>ha-anashim ha-yoshvim al ha-chomah</i> — the men sitting on the wall). The gruesome image that follows (eating their own excrement and drinking their own urine, v27) drives home the horror of a prolonged siege. This was sophisticated psychological warfare: the Rabshakeh was intentionally creating a wedge between the military/political leadership and the civilian population, hoping to generate popular pressure for surrender. The tactic of appealing directly to civilians over their leaders' heads is documented in other Assyrian diplomatic interactions.</p>",
        "28": "<p><b>v28 — The Rabshakeh stands and shouts in Hebrew</b><br>The shift to public proclamation in Hebrew (<i>Yehudit</i>) is deliberate and devastating. Having been told to use Aramaic, the Rabshakeh does the opposite. The shout (<i>va-yiqra be-qol gadol</i> — crying with a great voice) to the assembled population on the walls is an act of psychological warfare targeting the will to resist. The content (vv29-35) is carefully structured: first, a warning against trusting Hezekiah; then an offer of peace and prosperity; finally, a historical argument that no god has ever defeated Assyria.</p>",
        "29": "<p><b>v29 — 'Don't let Hezekiah mislead you; he cannot save you'</b><br>The Rabshakeh's direct attack on Hezekiah's authority: <i>al yashia' lachem Chizkiyahu</i> — 'Hezekiah cannot save you.' The word <i>nashia'</i> (deliver/save) is the vocabulary of divine deliverance — the Rabshakeh is using theological language to undermine Hezekiah's role as the trustworthy king. By framing Hezekiah as a deceiver (<i>yashia'</i> Hezekiah = he will lead you astray), the speech creates maximum suspicion of royal leadership at the moment when civilian trust in that leadership is most critical.</p>",
        "30": "<p><b>v30 — 'Don't trust the LORD saying Jerusalem will not fall'</b><br>The speech directly targets Hezekiah's theological argument: his claim that the LORD will certainly rescue Jerusalem. The Rabshakeh quotes the Yahwistic promise accurately — &#x201C;Jerusalem will certainly not fall to the king of Assyria&#x201D; — and then implicitly ridicules it by juxtaposing it with the historical record of Assyrian conquest (vv33-35). The tactic is to make the theological promise of divine protection appear as dangerous self-deception, and Hezekiah's reliance on it as royal irresponsibility toward the civilian population.</p>",
        "31": "<p><b>v31 — 'Make peace with me; eat from your vine and fig tree'</b><br>The offer of terms: <i>ashu itti</i> (make a blessing/peace with me — the word is <i>berakhah</i>, blessing). The promise to each person eating from his vine and fig tree and cistern is a deliberate echo of Solomon's golden age (1 Kings 4:25) — the Rabshakeh is using Israel's own covenantal blessing-language to describe Assyrian benevolence. The propaganda is sophisticated: it inverts the covenant promises, suggesting that submission to Assyria will provide exactly what faithfulness to YHWH promised. This is imperial theology appropriating Israelite imagery.</p>",
        "32": "<p><b>v32 — 'I will take you to a land like your own — choose life'</b><br>The deportation is presented as a positive option: a land of grain, wine, bread, vineyards, olive trees, and honey — <i>bacharu va-chayyu ve-al temotu</i> (choose and live and do not die). The phrase &#x201C;a land like your own&#x201D; is a deliberate echo of Deuteronomy&#x2019;s promised land descriptions. The &#x201C;choose life&#x201D; (<i>bachar va-chayyu</i>) echoes Moses' own language in Deut 30:19: &#x201C;Choose life.&#x201D; The Rabshakeh's speech appropriates Mosaic covenant language to argue for submission to Assyria — one of the most audacious rhetorical moves in the biblical text.</p>",
        "33": "<p><b>v33 — 'Has any god ever rescued his land from Assyria?'</b><br>The comparative theology argument: has any god of the nations delivered his land from Assyrian power? This argument reflects genuine Assyrian imperial theology — Assur, the chief Assyrian deity, was understood as superior to all other national gods. Assyrian royal inscriptions regularly describe conquest as Assur's triumph over the gods of conquered nations. The Rabshakeh's argument was historically compelling: Assyria had indeed conquered nation after nation whose gods did not protect them. The theological challenge is real: if YHWH is just another national deity, the historical record is against Judah.</p>",
        "34": "<p><b>v34 — Gods of Hamath, Arpad, Sepharvaim named and mocked</b><br>The roster of defeated gods and nations: Hamath (on the Orontes, conquered by Sargon II in 720 BCE), Arpad (near Aleppo, conquered by Tiglath-Pileser III in 740 BCE), Sepharvaim (possibly Sibraim in Syria), Hena and Ivvah (locations uncertain). Each named city represents a national god who failed to prevent Assyrian conquest. The implicit argument: if the gods of Hamath and Arpad could not prevent their nations&#x2019; destruction, why should YHWH be different? The challenge to YHWH's uniqueness is what makes chapter 19&#x2019;s response so important theologically.</p>",
        "35": "<p><b>v35 — 'How will the LORD rescue Jerusalem from me?'</b><br>The climax of the Rabshakeh's speech: the direct challenge to YHWH. The question is unanswerable on human political grounds — no military force in the Levant could match Assyria. The speech works by systematically eliminating every possible human source of trust and then turning that logic against YHWH as if he were merely another national deity. The Hezekiah narrative's response (through Isaiah's oracle in ch19) will argue precisely that YHWH is categorically different from the gods of Hamath and Arpad — not a national deity among others but the creator of heaven and earth.</p>",
        "36": "<p><b>v36 — The people remained silent; the king had commanded silence</b><br><i>Ve-haamu hacharishu</i> — 'the people were silent.' The silence is disciplined, not cowardly — Hezekiah had ordered them not to answer (<i>al ta'anu oto davar</i>). The tactic of ordered silence in the face of propaganda was wise: any response would be used by the Rabshakeh as further material for argument. The wall-sitting population's enforced silence prevented the psychological wedge from being driven between citizen and king. The contrast with the Rabshakeh's loud shouting creates a dramatic tableau: Assyrian noise versus Judean silence, the external voice of worldly power versus the inner quiet of those who wait on God.</p>",
        "37": "<p><b>v37 — The delegation returns to Hezekiah with torn garments</b><br>Eliakim, Shebna, and Joah return to Hezekiah with <i>qeru'ei vegadim</i> (torn garments) and report the Rabshakeh's words. The torn garments are the sign of grief and distress — the officials have internalized the gravity of what they heard. The report to Hezekiah sets the scene for ch19: a king who receives terrible news and takes it immediately to the house of the LORD (19:1). The same three officials who went to negotiate will now serve as messengers to Isaiah, connecting the diplomatic and prophetic responses.</p>"
    },
    "19": {
        "1": "<p><b>v1 — Hezekiah tears his clothes and goes to the temple</b><br>Hezekiah's response to the crisis is immediate and characteristic: he tears his clothes (<i>va-yiqra et begadav</i>), puts on sackcloth (<i>va-yitkas ba-saq</i>), and goes to the house of the LORD. The sequence of mourning-gestures (torn garments, sackcloth, temple) is the classic OT response to national emergency — the same pattern as Josiah's response to the law-book discovery (2 Kings 22:11-20). The temple as the first recourse in crisis reflects the centralization of worship Hezekiah himself accomplished; he goes to the place he has designated as the sole legitimate worship site.</p>",
        "2": "<p><b>v2 — The delegation to Isaiah: senior priests in sackcloth</b><br>Hezekiah sends Eliakim, Shebna, and the senior priests (<i>ha-kohanim ha-zeqenim</i>) — all wrapped in sackcloth — to Isaiah son of Amoz. The prophetic consultation in national emergency was a standard institution in ancient Israel (cf. 1 Kings 22:5-28; 2 Chr 18:4). Isaiah's position in Jerusalem gave him privileged access to the royal court; Isaiah 1-39 describes his extended ministry during the reigns of Uzziah, Jotham, Ahaz, and Hezekiah. The parallel account in Isaiah 36-39 is almost verbatim to 2 Kings 18-20, with the significant addition of Hezekiah's thanksgiving psalm (Isa 38:9-20).</p>",
        "3": "<p><b>v3 — A day of distress, rebuke, and disgrace; children at the birth-point</b><br>Hezekiah's message to Isaiah describes the crisis using the metaphor of a woman in labor who lacks strength to deliver (<i>u-koach ein le-leidah</i>). The metaphor appears in other crisis contexts (Isa 37:3; cf. Isa 13:8; 26:17-18; Mic 4:9-10) and captures the moment when the crisis is most acute but resolution has not come — the pain is at maximum but the outcome uncertain. The three words — <i>tzarah</i> (distress), <i>tokhechah</i> (rebuke/chastisement), and <i>ne'atzah</i> (contempt/disgrace) — describe the multi-layered crisis: external military threat, possible divine rebuke, and national humiliation.</p>",
        "4": "<p><b>v4 — 'Perhaps the LORD your God will rebuke the living God's mocker'</b><br>Hezekiah's petition to Isaiah includes the phrase <i>Elohei chay</i> (the living God) — a title that directly addresses the Rabshakeh's challenge. The contrast is explicit: the gods of Hamath and Arpad are not living gods (v18: they are wood and stone); YHWH is <i>Elohim chay</i> — alive, capable of hearing and responding. The careful phrase <i>'ulay yishma YHWH Elohekha'</i> — 'perhaps the LORD your God will hear' — is a petition hedged with appropriate humility, not presumption, which is theologically significant: Hezekiah does not assume he deserves divine intervention.</p>",
        "5": "<p><b>v5 — The servants come to Isaiah</b><br>The brief transitional verse confirms the delegation has arrived. The simplicity of <i>va-yavo'u avdei ha-melekh Chizkiyahu el Yeshayahu</i> — 'the servants of King Hezekiah came to Isaiah' — marks the movement from palace to prophet. In the narrative structure, this creates a pivot: the human political response (Hezekiah's submission and distress) now meets the prophetic word. Isaiah's response will reframe the entire crisis from a military problem to a theological one: not Judah versus Assyria but the living God versus the boastful human power.</p>",
        "6": "<p><b>v6 — Isaiah's oracle: 'Do not be afraid of the servant-boys' words'</b><br>Isaiah's response is direct: <i>al-tira</i> (do not be afraid). The oracle diminishes the Rabshakeh's status — the word <i>na'ar</i> (young men/servant-boys) rather than officials or generals — expressing prophetic contempt for the Rabshakeh's speech. The phrase &#x201C;the words of the servant-boys of the king of Assyria who blasphemed me&#x201D; — <i>nidafu</i> (blasphemed/mocked) — frames the speech as blasphemy against YHWH, not merely political challenge to Judah. The classification of the Rabshakeh's speech as divine blasphemy establishes the terms for the divine response: it is not a political problem but a theological one that God will address directly.</p>",
        "7": "<p><b>v7 — 'I will put a spirit in him and he will return and fall by the sword'</b><br>The divine prediction: God will put a <i>ruach</i> (spirit/wind/impulse) in Sennacherib causing him to hear a rumor (<i>shemu'ah</i>) and return to his land, where he will fall by the sword. This prediction is fulfilled in vv36-37: Sennacherib does return (triggered by v9's rumor about Tirhakah), and is killed by his sons in his homeland. The <i>ruach</i> is not a spirit of prophecy but of distraction — an inner impulse that redirects the king's attention. The word <i>shemu'ah</i> (report/rumor) is the same word used in v9 for the intelligence about Tirhakah. The divine mechanism is the providential use of political events.</p>",
        "8": "<p><b>v8 — Rabshakeh returns to find Sennacherib at Libnah</b><br>The Rabshakeh returns and finds Sennacherib has moved from Lachish to Libnah — a city in the Shephelah (Josh 10:29-30; 15:42), probably modern Tell Burna or Tell es-Safi (Gath). The movement from Lachish to Libnah suggests Sennacherib was continuing military operations in the lowlands while the Jerusalem delegation was underway. The siege of Libnah was concurrent with the Rabshakeh's diplomatic mission, giving context to the complexity of Sennacherib's 701 campaign: multiple cities being engaged simultaneously.</p>",
        "9": "<p><b>v9 — Tirhakah king of Ethiopia: the chronological problem</b><br>When Sennacherib hears that <i>Tirhakah king of Ethiopia</i> (<i>Tirhaqah melekh Kush</i>) has come out to fight him, he sends a second letter to Hezekiah. Tirhakah (Taharqa in Egyptian) was the third king of Egypt's 25th (Kushite) dynasty, reigning 690–664 BCE. The chronological problem: Sennacherib's 701 BCE campaign predates Tirhakah's reign by 11 years. Scholars propose: (1) he commanded forces before becoming king (he would have been c.19 at the time — an early command role is plausible); (2) his title reflects his later royal status; (3) there was a second Sennacherib campaign. The issue remains debated.</p>",
        "10": "<p><b>v10 — The second letter: 'Don't let your God deceive you'</b><br>Sennacherib's second communication shifts from the public oratory of the Rabshakeh to a written letter (<i>sefarim</i>). The letter claims Hezekiah's God is deceiving him — <i>yashia'kha Elohekha</i> (your God is misleading you). The letter reuses the Rabshakeh's language of deception/misleading. The shift from oral proclamation to written document is significant in the history of political communication — the letter allows the message to be read privately and repeatedly, creating different psychological pressure than the public shout. Hezekiah will take this letter to the temple and spread it before the LORD (v14) — treating a political document as a theological challenge.</p>",
        "11": "<p><b>v11 — 'You have heard what Assyrian kings did — utterly destroying all nations'</b><br>The historical claim: the kings of Assyria have <i>hachatem</i> (devoted to destruction/utterly destroyed) all the nations. The word <i>hacharam</i> is the same root as the Israelite concept of <i>cherem</i> (ban/devotion to destruction) — the Rabshakeh's letter appropriates the covenantal destruction-language to describe Assyrian conquest. Whether this reflects deliberate irony (using Israel's holy war vocabulary) or simply the fact that destruction is destruction regardless of who performs it, the effect is to cast Assyrian conquest in the same totalizing terms as the Canaanite conquest.</p>",
        "12": "<p><b>v12 — Gozan, Haran, Rezeph, Eden in Telassar — no god delivered them</b><br>The catalog of conquered regions: Gozan (Tell Halaf, Khabur River area — confirmed as Assyrian territory by cuneiform records), Haran (the famous city on the Balikh River, significant for Abraham's departure — Gen 11:31-12:1), Rezeph (Rasappa in Assyrian sources, modern Resafa in Syria), and the people of Eden in Telassar (possibly the Bit-Adini, an Aramaean tribal state on the middle Euphrates, conquered by Shalmaneser III). Each name in the list is identifiable from Assyrian cuneiform records, confirming the historical accuracy of the catalog.</p>",
        "13": "<p><b>v13 — Kings of Hamath, Arpad, Sepharvaim — where are they?</b><br>The rhetorical question echoes the Rabshakeh's earlier list (18:34). Hamath had an anti-Assyrian king Yau-bi'di who was defeated by Sargon II (720 BCE); Arpad was conquered by Tiglath-Pileser III (740 BCE). The question &#x201C;where are the kings?&#x201D; implies they no longer exist as independent rulers — they have been removed, executed, or absorbed into the Assyrian provincial system. The implied answer: they are gone. The implicit challenge: Hezekiah will be next unless he submits. The list of fallen kings is designed to project historical inevitability onto Judah's situation.</p>",
        "14": "<p><b>v14 — Hezekiah spreads the letter before the LORD in the temple</b><br><i>Va-yifros Chizkiyahu et ha-sefarim lifnei YHWH</i> — 'Hezekiah spread out the letters before the LORD.' This act — taking a political document and laying it open before God — is one of the most vivid acts of prayer in the OT. It treats YHWH as a present king who can read the letter, see the threat, and respond to it. The act presupposes that the political crisis is fundamentally a theological confrontation: Sennacherib&#x2019;s letter is not primarily addressed to Hezekiah but to YHWH. The temple becomes the throne room of the true King who will judge the matter.</p>",
        "15": "<p><b>v15 — Hezekiah's prayer: 'You alone are God over all kingdoms'</b><br>Hezekiah's prayer begins with the divine address: <i>YHWH Elohei Yisrael yoshev ha-keruvim</i> — 'LORD God of Israel, enthroned on the cherubim.' The cherub-throne is the ark of the covenant's imagery (1 Sam 4:4; 2 Sam 6:2; Ps 80:1; 99:1) — the place where YHWH is conceived as enthroned in the heavenly throne room, represented on earth by the ark. Then the crucial monotheistic claim: <i>attah-hu ha-Elohim levadekha le-khol mamlakhot ha-aretz</i> — 'you alone are God over all the kingdoms of the earth.' This directly answers the Rabshakeh's implicit comparative theology: YHWH is not one god among others but the sole God of all nations.</p>",
        "16": "<p><b>v16 — 'Incline your ear and hear; open your eyes and see'</b><br>The petition uses the classical language of divine attention: <i>hatteh YHWH oznekha u-shma</i> (incline your ear and hear) and <i>pekach YHWH einekha ur'eh</i> (open your eyes and see). The anthropomorphic language is common in petitionary prayer (Pss 17:6; 31:2; 71:2; 86:1) — it presupposes a God who can choose to attend or not, and who must be petitioned to direct his attention to the current crisis. The specific objects of divine attention: Sennacherib's words (<i>kol divrei Sennacherib</i>) and his mockery of the living God (<i>asher shalach le-charef Elohim chay</i>).</p>",
        "17": "<p><b>v17 — 'It is true, LORD, that the Assyrian kings have destroyed the nations'</b><br>Hezekiah's prayer includes a remarkable concession: <i>achen YHWH</i> — 'it is true, LORD.' He does not dispute the historical facts the Rabshakeh cited. Yes, the Assyrian kings destroyed nation after nation. The prayer is not based on a denial of Assyria's military record but on a theological distinction: what made those conquests possible is different from what Judah is relying on. The concession of historical fact before making the theological distinction is rhetorically honest — Hezekiah is not appealing to divine help on the grounds that Assyria is militarily weak, but on the grounds that YHWH is categorically different.</p>",
        "18": "<p><b>v18 — 'Their gods were wood and stone — no gods at all'</b><br>The explanation: the Assyrian kings defeated those nations and cast their gods into the fire — <i>ki lo Elohim hemah ki im ma'aseh yedei adam etz va-aven</i> — 'because they were not gods at all, merely the work of human hands, wood and stone.' This is the classic OT polemic against idolatry (cf. Isa 44:9-20; Ps 115:4-8; Deut 4:28). The argument is logical: Assyria defeated those nations because their gods were no gods. But YHWH is not the work of human hands. The defeat of the idol-worshiping nations cannot be extrapolated to the defeat of the living God's people — the comparison breaks down at a categorical level.</p>",
        "19": "<p><b>v19 — 'Deliver us so all the kingdoms may know you alone are God'</b><br>The climax of Hezekiah's petition: <i>hoshine'u mi-yado</i> (deliver us from his hand) — not for Judah's sake primarily, but <i>veyede'u kol-mamlakhot ha-aretz ki attah YHWH Elohim levadekha</i> — 'so that all the kingdoms of the earth may know that you, LORD, are God alone.' The universal scope of the requested deliverance is striking: Hezekiah prays for a miracle whose purpose is global theological testimony. This transforms the siege of Jerusalem from a local military crisis into a cosmic theological event — the vindication of monotheism before the watching nations.</p>",
        "20": "<p><b>v20 — Isaiah's oracle response: 'I have heard your prayer'</b><br>Isaiah sends word to Hezekiah: <i>shama'ti</i> — 'I have heard.' The divine response to Hezekiah's temple prayer is immediate — the prayer is heard (the very thing the temple dedication in 1 Kings 8 repeatedly prayed for: 'hear in heaven and forgive'). The response comes through the prophet Isaiah, whose oracle (vv21-34) is one of the most sustained prophetic poems in the OT, combining taunting address to Sennacherib and promise of deliverance to Judah. The parallel in Isaiah 37 is nearly identical.</p>",
        "21": "<p><b>v21 — The virgin daughter of Zion despises and mocks Sennacherib</b><br>The oracle opens with a personified Zion (<i>betulat bat-Tzion</i> — virgin daughter of Zion) despising and mocking Sennacherib, shaking her head behind him. The image of a city as a daughter/young woman is common in prophetic literature (Isa 1:8; 16:1; 23:12; Jer 46:11; Lam 1:15). Here Zion is not prostrate before the conqueror but contemptuous — a reversal of the expected posture of a besieged city. The poetry begins with the defeated image of Sennacherib&#x2019;s expectations and immediately inverts it: Jerusalem has not bowed, and in the prophetic vision it is Sennacherib who is reduced to an object of contempt.</p>",
        "22": "<p><b>v22 — 'You have mocked the Holy One of Israel'</b><br>The oracle identifies the true target of Sennacherib's campaign: <i>et mi cheraftah ve-gidafta... et Qedosh Yisrael</i> — 'whom have you mocked and blasphemed? The Holy One of Israel.' <i>Qedosh Yisrael</i> (the Holy One of Israel) is a characteristically Isaianic divine title — it appears approximately 25 times in Isaiah (both 1-39 and 40-66) and rarely elsewhere. The title emphasizes divine transcendence and separateness from all that is merely human and finite. Sennacherib's arrogance has not merely challenged Judah — he has blasphemed the categorically different God of all creation.</p>",
        "23": "<p><b>v23 — Sennacherib's boast: I climbed to Lebanon's heights by my messengers</b><br>The oracle voices Sennacherib's boasting in first person: through messengers he claims to have climbed the highest mountains, felled Lebanon&#x2019;s cedars and cypresses, and reached Carmel's heights and the waters of the rivers. The boasting reflects actual Assyrian royal ideology: Assyrian annals are full of first-person royal boasting (<i>ana rabuti biti Ashur</i> — &#x201C;at the great command of Assur&#x201D;) claiming divine sanction for military achievements. The imagery of cutting down the tallest trees (cedar of Lebanon) is also used metaphorically in Assyrian texts for defeating the greatest kings.</p>",
        "24": "<p><b>v24 — 'I dug wells and drank foreign water; I dried up Egypt's streams'</b><br>The boast continues: crossing deserts by digging cisterns, drying up Egypt's Nile channels with the soles of his feet. These are hyperbolic claims of world-dominating power — the ability to traverse the desert (a classic Assyrian military challenge) and drain Egypt's agricultural lifeline. The specific mention of Egypt is significant: Sennacherib never actually conquered Egypt (that was Esarhaddon in 671 BCE and Ashurbanipal), but the oracle voices the claim as it would be made by an Assyrian great king with maximum ambition.</p>",
        "25": "<p><b>v25 — 'Have you not heard? I ordained long ago what I would do'</b><br>God's response to Sennacherib's boasting: <i>ha-lo shama'ta</i> — 'have you not heard?' The question implies Sennacherib should have known but did not. Then the theological reframe: God determined long ago (<i>me-yamim qedem</i>) what Sennacherib would do; from ancient times (<i>mi-qedem</i>) it was planned. Sennacherib&#x2019;s conquests are not his achievement but God&#x2019;s purpose working through him — an Isaianic theme (cf. Isa 10:5-19: Assyria as the rod of God&#x2019;s anger). The Assyrian empire was not the autonomous achievement of Assyrian military power but the instrument of divine historical purpose.</p>",
        "26": "<p><b>v26 — The conquered peoples were powerless like grass on rooftops</b><br>The conquered nations had &#x201C;little power&#x201D; (<i>qetzrei yad</i> — short of hand/powerless) because God had already determined they would be defeated. They are compared to <i>esev sadeh</i> (grass of the field) and <i>yereq deshe</i> (green shoots) — specifically like grass on rooftops (<i>deshot geggot</i>), which sprouts quickly in morning dew but is scorched before it matures. The rooftop-grass image is used in Psalm 129:6 for enemies that will be withered. The nations fell not because Assyria was strong but because God had decreed their overthrow.</p>",
        "27": "<p><b>v27 — 'I know your dwelling, your going out and coming in, and your rage'</b><br>YHWH&#x2019;s omniscience is asserted: <i>vedam I know your dwelling (<i>shivtekha</i>) and your going out (<i>tzet'kha</i>) and your coming in (<i>bo'ekha</i>).</i> God&#x2019;s knowledge of Sennacherib&#x2019;s movements and inner life (the <i>rigzekha elai</i> — your rage against me) positions the divine as the all-seeing sovereign over the Assyrian king&#x2019;s entire existence. The contrast with Sennacherib&#x2019;s boasting (I climbed the mountains; I dried up the rivers) is sharp: what Sennacherib sees as his own autonomous achievement, God sees as fully known and supervised.</p>",
        "28": "<p><b>v28 — The hook in the nose: Sennacherib will be sent back</b><br><i>Ve-samtiy chachiy be-appekha u-metsiltiy be-sefatekha</i> — 'I will put my hook in your nose and my bridle in your mouth.' The image of hook-and-bridle control is drawn from Assyrian military iconography: Assyrian reliefs show conquered kings led by hooks through their noses or lips. God appropriates this Assyrian image of conquest and applies it to Sennacherib himself — the conqueror will be controlled and redirected like a captured animal. <i>Va-hashivotikha ba-derekh asher bata bah</i> — 'I will send you back the way you came' — the oracle promises a reversal without a battle.</p>",
        "29": "<p><b>v29 — The agricultural sign: three-year recovery sequence</b><br>A sign (<i>ot</i>) for Hezekiah: this year eat what grows on its own (<i>saphiach</i> — volunteer growth from unharvested grain), next year what springs from that (<i>sachiach</i> — growth from the saphiach), and in the third year sow, reap, plant vineyards, and eat their fruit. The three-year sign implies that agricultural disruption from the siege will take two years to overcome before normal cultivation resumes. The gradual restoration — volunteer growth, then secondary volunteer, then deliberate planting — reflects the actual agricultural recovery timeline after military disruption. Normal farming requires safety and stability; the sign promises enough time will pass for recovery.</p>",
        "30": "<p><b>v30 — The surviving remnant will take root downward and bear fruit upward</b><br><i>Ve-yosefah peletah beit Yehudah ha-nishe'arah shoresh lemattah ve-asah feri lema'lah</i> — 'The surviving remnant of the house of Judah will again take root downward and bear fruit upward.' The remnant (<i>she'erit</i>) theology is central to Isaiah — a faithful remnant will survive judgment and become the seedbed of restoration (cf. Isa 10:20-22; 11:11-16; 37:31-32). The root/fruit imagery speaks of organic growth from small beginnings: what looked like a withered stump will send down deep roots and bear fruit. This is the same imagery Isaiah uses for the shoot from the stump of Jesse (Isa 11:1).</p>",
        "31": "<p><b>v31 — 'The zeal of the LORD of hosts will accomplish this'</b><br><i>Ki min-Yerushalayim tetzei she'erit u-mi-har-Tzion peletah qin'at YHWH tzeva'ot ta'aseh zot</i> — 'For a remnant will come out from Jerusalem and survivors from Mount Zion. The zeal of the LORD of hosts will accomplish this.' The identical phrase <i>qin'at YHWH tzeva'ot</i> (the zeal of the LORD of hosts) appears in Isa 9:7 — the oracle about the prince of peace whose kingdom grows forever. The zeal that establishes the eternal Davidic kingdom is the same divine energy that drives the current deliverance. The phrase connects the immediate historical promise to the larger eschatological horizon.</p>",
        "32": "<p><b>v32 — Sennacherib will not enter the city or shoot an arrow here</b><br>The oracle specifies Sennacherib's defeat in technical military terms: he will not enter the city, shoot an arrow here, come before it with a shield, or cast up a siege ramp (<i>loh-yishpokh aleha solelah</i>). The siege ramp (<i>solelah</i>) was the standard Assyrian siege technique — a massive earthen ramp built up against city walls to allow assault troops to breach the fortifications. The Lachish relief shows exactly this technique being used at Lachish. Jerusalem will be spared this very thing — no arrow, no shield, no ramp, no entry. The promise is absolute and specific.</p>",
        "33": "<p><b>v33 — 'He will go back the same way he came and not enter this city'</b><br>The symmetry of departure and arrival: <i>ba-derekh asher-ba bah yashuv</i> — 'by the way he came he will return.' No siege, no assault, no conquest — Sennacherib will simply reverse course. The fulfillment is recorded in v36: <i>va-yetze va-yelekh va-yashuv Sennacherib</i> — 'Sennacherib broke camp, went away, and returned.' The Sennacherib Annals do not describe a defeat or retreat — they claim a successful siege and tribute payment, but conspicuously stop short of claiming Jerusalem's conquest (unlike all the other cities in the campaign). The Assyrian record&#x2019;s silence about Jerusalem&#x2019;s fall is itself evidence of something unexpected occurring.</p>",
        "34": "<p><b>v34 — 'I will defend this city for my own sake and for David's sake'</b><br><i>Ve-ganoti al ha-ir ha-zot lehoshi'ah le-ma'ani u-le-ma'an David avdi</i> — 'I will defend this city to save it, for my own sake and for the sake of my servant David.' Two reasons: divine honor (<i>le-ma'ani</i> — for my own sake, my name, my reputation) and Davidic covenant (<i>le-ma'an David avdi</i>). The divine honor motive reflects the Isaianic concern for YHWH&#x2019;s name among the nations — the question raised by the Rabshakeh (which of the gods rescued his land?) will be answered by YHWH&#x2019;s defense of Jerusalem. The Davidic covenant motive reflects the Deuteronomistic faith that God&#x2019;s commitment to David&#x2019;s dynasty transcends the failures of individual kings.</p>",
        "36": "<p><b>v36 — Sennacherib breaks camp and returns to Nineveh</b><br><i>Va-yisa va-yelekh va-yashuv Sennacherib</i> — 'Sennacherib broke camp and went and returned to Nineveh.' The three verbs are terse and definitive: he lifted camp, went, returned. No conquest of Jerusalem, no triumph. Sennacherib&#x2019;s own Annals describe the campaign&#x2019;s Judean portion as successful in terms of tribute and captured cities but make no claim to taking Jerusalem itself — they say he &#x201C;shut up Hezekiah in Jerusalem like a bird in a cage.&#x201D; The cage metaphor implies encirclement, not conquest. The biblical account and the Assyrian Annals agree on the basic fact: Jerusalem was not taken.</p>",
        "37": "<p><b>v37 — Sennacherib killed by his sons in Nineveh; Esarhaddon succeeds</b><br>While worshiping in the temple of Nisroch (<i>Nisrokh</i>) his god, Sennacherib is killed by his sons Adrammelech (<i>Adrammelekh</i>) and Sharezer (<i>Shar'etzer</i>), who flee to Ararat (Urartu). Esarhaddon (<i>Esar-Chaddon</i>) his son then becomes king. This is confirmed by the Babylonian Chronicle: Sennacherib was indeed murdered by one of his sons in 681 BCE, approximately 20 years after the 701 campaign. The Assyrian sources describe a succession crisis; the biblical account attributes the act to two specific sons. Esarhaddon (681–669 BCE) then reunified the empire and later conquered Egypt in 671 BCE. The god Nisroch is uncertain — possibly Nusku, the fire god, or a variant of Marduk or Ninurta.</p>"
    }
}

def main():
    existing = load_comm('mkt-context', '2kings')
    merge_comm(existing, TWO_KINGS_CONTEXT)
    save_comm('mkt-context', '2kings', existing)
    il = json.loads((ROOT / 'data/interlinear/2kings.json').read_text())
    all_ok = True
    for ch in ['18', '19']:
        got = set(existing.get(ch, {}).keys())
        need = set(il[ch].keys())
        missing = need - got
        if missing:
            print(f'  ch{ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'  ch{ch}: {len(got)} verses complete')
    if all_ok:
        print('2 Kings context fill (chs 18–19) done. All verses present.')

if __name__ == '__main__':
    main()
